   376→// ValidateRecipe validates a recipe without storing it
   377→func (h *Handler) ValidateRecipe(c *fiber.Ctx) error {
   378→	var recipe models.Recipe
   379→	if err := c.BodyParser(&recipe); err != nil {
   380→		return c.Status(400).JSON(fiber.Map{
   381→			"error":   "Invalid recipe data",
   382→			"details": err.Error(),
   383→		})
   384→	}
   385→
   386→	// Basic validation
   387→	if err := recipe.Validate(); err != nil {
   388→		return c.Status(400).JSON(fiber.Map{
   389→			"error":   "Recipe validation failed",
   390→			"details": err.Error(),
   391→			"valid":   false,
   392→		})
   393→	}
   394→
   395→	// Additional validation checks
   396→	warnings := []string{}
   397→
   398→	// Check for missing optional but recommended fields
   399→	if recipe.Metadata.MinPlatform == "" {
   400→		warnings = append(warnings, "Missing minimum platform version")
   401→	}
   402→	if len(recipe.Metadata.Tags) == 0 {
   403→		warnings = append(warnings, "No tags specified")
   404→	}
   405→	if recipe.Metadata.License == "" {
   406→		warnings = append(warnings, "No license specified")
   407→	}
   408→
   409→	// Check step configurations
   410→	for i, step := range recipe.Steps {
   411→		if step.Timeout.Duration == 0 {
   412→			warnings = append(warnings, "Step "+strconv.Itoa(i+1)+" ("+step.Name+") has no timeout specified")
   413→		}
   414→
   415→		// OpenRewrite-specific validation
   416→		if step.Type == models.StepTypeOpenRewrite {
   417→			if recipe, ok := step.Config["recipe"].(string); !ok || recipe == "" {
   418→				warnings = append(warnings, "Step "+strconv.Itoa(i+1)+" ("+step.Name+") is OpenRewrite type but missing 'recipe' config")
   419→			}
   420→			if len(recipe.Metadata.Languages) == 0 || (recipe.Metadata.Languages[0] != "java" && recipe.Metadata.Languages[0] != "kotlin") {
   421→				warnings = append(warnings, "OpenRewrite recipe should specify 'java' or 'kotlin' as language")
   422→			}
   423→		}
   424→	}
   425→
   426→	response := fiber.Map{
   427→		"valid":   true,
   428→		"message": "Recipe is valid",
   429→		"summary": fiber.Map{
   430→			"name":       recipe.Metadata.Name,
   431→			"version":    recipe.Metadata.Version,
   432→			"steps":      len(recipe.Steps),
   433→			"languages":  recipe.Metadata.Languages,
   434→			"categories": recipe.Metadata.Categories,
   435→		},
   436→	}
   437→
   438→	if len(warnings) > 0 {
   439→		response["warnings"] = warnings
   440→	}
   441→
   442→	return c.JSON(response)
   443→}
