   445→// DownloadRecipe returns a recipe in YAML format
   446→func (h *Handler) DownloadRecipe(c *fiber.Ctx) error {
   447→	recipeID := c.Params("id")
   448→
   449→	// Get recipe from storage backend
   450→	recipe, err := h.getRecipeWithStorage(c.Context(), recipeID)
   451→	if err != nil {
   452→		return c.Status(404).JSON(fiber.Map{
   453→			"error":   "Recipe not found",
